#include <bits/stdc++.h>

using namespace std;

void solve() {
    int N, Q;
    cin >> N >> Q;

    vector < int > F(N);
    // Read the elements of the sequence
    for (int i = 0; i < N; i++) {
        cin >> F[i];
    }

    // Calculate Total XOR
    int totalXor = 0;
    for (int i = 0; i < N; i++) {
        totalXor ^= F[i];
    }

    // Initialize S values
    vector < int > S(N + 2);
    S[0] = 0; // S_0 = 0
    for (int i = 1; i <= N; i++) {
        S[i] = S[i - 1] ^ F[i - 1];
    }
    S[N + 1] = totalXor; // S_(N+1) = Total XOR

    // Process each query
    for (int i = 0; i < Q; i++) {
        int k;
        cin >> k; // Read the query value k
        // Output S_k mod (N + 1)
        cout << S[k % (N + 1)] << endl;
    }
}

int main() {
    solve(); // Call the solve method
    return 0;
}

