code.JavaScript:
const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function solve(N, Q, F, queries) {
    // Calculate Total XOR
    let totalXor = 0;
    for (let i = 0; i < N; i++) {
        totalXor ^= F[i];
    }

    // Initialize S values
    const S = new Array(N + 2).fill(0);
    for (let i = 1; i <= N; i++) {
        S[i] = S[i - 1] ^ F[i - 1];
    }
    S[N + 1] = totalXor; // S_(N+1) = Total XOR

    // Process each query
    const results = queries.map(k => S[k % (N + 1)]);
    console.log(results.join('\n'));
}

function main() {
    let input = '';
    rl.on('line', line => {
        input += line + '\n';
    });

    rl.on('close', () => {
        const data = input.trim().split('\n');
        const [N, Q] = data[0].split(' ').map(Number);
        const F = data[1].split(' ').map(Number);
        const queries = data.slice(2).map(Number);

        solve(N, Q, F, queries); // Call the solve function with parsed input
    });
}

main(); // Start the program
